UPDATE words SET example_en_2 = 'She asked her supervisor for advice on the peer review process.', example_ko_2 = '그녀는 지도 교수에게 동료 심사 과정에 대한 조언을 구했어요.', example_en_3 = 'The journal requires double-blind peer review.', example_ko_3 = '그 학술지는 이중 맹검 동료 심사를 요구해요.', example_en_4 = 'Peer review helps to improve the quality of academic writing.', example_ko_4 = '동료 심사는 학술 글쓰기의 질을 향상시키는 데 도움이 돼요.', example_en_5 = 'After peer review, she made significant revisions to her paper.', example_ko_5 = '동료 심사 후 그녀는 논문을 크게 수정했어요.' WHERE id = 'w_academic_B2_01';

UPDATE words SET example_en_2 = 'He submitted his dissertation two months before the deadline.', example_ko_2 = '그는 마감일 두 달 전에 학위 논문을 제출했어요.', example_en_3 = 'Her dissertation explored the role of identity in language learning.', example_ko_3 = '그녀의 학위 논문은 언어 학습에서 정체성의 역할을 탐구했어요.', example_en_4 = 'Writing a dissertation requires months of research.', example_ko_4 = '학위 논문을 작성하는 데는 수개월의 연구가 필요해요.', example_en_5 = 'The dissertation committee praised her original methodology.', example_ko_5 = '논문 심사 위원회는 그녀의 독창적인 방법론을 칭찬했어요.' WHERE id = 'w_academic_B2_02';

UPDATE words SET example_en_2 = 'The research used a Vygotskian framework.', example_ko_2 = '연구는 비고츠키의 틀을 사용했어요.', example_en_3 = 'Select a theoretical framework that fits your research questions.', example_ko_3 = '연구 질문에 맞는 이론적 틀을 선택해 주세요.', example_en_4 = 'The conceptual framework guided the data collection phase.', example_ko_4 = '개념적 틀이 데이터 수집 단계를 안내했어요.', example_en_5 = 'She justified her choice of framework in the literature review.', example_ko_5 = '그녀는 문헌 검토에서 틀 선택을 정당화했어요.' WHERE id = 'w_academic_B2_03';

UPDATE words SET example_en_2 = 'The study challenges the dominant paradigm in linguistics.', example_ko_2 = '연구는 언어학의 지배적인 패러다임에 도전해요.', example_en_3 = 'A paradigm shift occurs when new evidence overturns old assumptions.', example_ko_3 = '패러다임 전환은 새로운 증거가 오래된 가정을 뒤집을 때 일어나요.', example_en_4 = 'Kuhn introduced the concept of a scientific paradigm.', example_ko_4 = '쿤은 과학적 패러다임의 개념을 도입했어요.', example_en_5 = 'This finding may trigger a paradigm shift in the field.', example_ko_5 = '이 발견은 분야에서 패러다임 전환을 일으킬 수 있어요.' WHERE id = 'w_academic_B2_04';

UPDATE words SET example_en_2 = 'She conducted qualitative interviews with fifteen teachers.', example_ko_2 = '그녀는 15명의 교사와 질적 인터뷰를 진행했어요.', example_en_3 = 'Qualitative research focuses on meaning and experience.', example_ko_3 = '질적 연구는 의미와 경험에 중점을 둬요.', example_en_4 = 'He used qualitative methods to explore student motivation.', example_ko_4 = '그는 학생 동기 부여를 탐구하기 위해 질적 방법을 사용했어요.', example_en_5 = 'Qualitative findings are presented as themes, not numbers.', example_ko_5 = '질적 연구 결과는 숫자가 아닌 주제로 제시돼요.' WHERE id = 'w_academic_B2_05';

UPDATE words SET example_en_2 = 'The quantitative study involved 1,000 participants.', example_ko_2 = '양적 연구는 1,000명의 참가자를 포함했어요.', example_en_3 = 'Quantitative research uses statistical methods to test hypotheses.', example_ko_3 = '양적 연구는 가설을 검증하기 위해 통계적 방법을 사용해요.', example_en_4 = 'She combined qualitative and quantitative data for a fuller picture.', example_ko_4 = '그녀는 더 완전한 그림을 위해 질적·양적 데이터를 결합했어요.', example_en_5 = 'Quantitative results are easier to replicate than qualitative ones.', example_ko_5 = '양적 결과는 질적 결과보다 재현하기 더 쉬워요.' WHERE id = 'w_academic_B2_06';

UPDATE words SET example_en_2 = 'A course in epistemology is required for doctoral students.', example_ko_2 = '인식론 과목은 박사과정 학생들에게 필수예요.', example_en_3 = 'Epistemology asks: how do we know what we know?', example_ko_3 = '인식론은 "우리는 우리가 아는 것을 어떻게 아는가?"라고 물어요.', example_en_4 = 'His doctoral thesis was grounded in social epistemology.', example_ko_4 = '그의 박사 논문은 사회적 인식론에 기반했어요.', example_en_5 = 'Epistemology shapes the way researchers design their studies.', example_ko_5 = '인식론은 연구자들이 연구를 설계하는 방식을 형성해요.' WHERE id = 'w_academic_B2_07';

UPDATE words SET example_en_2 = 'This inference is not supported by the available data.', example_ko_2 = '이 추론은 이용 가능한 데이터에 의해 뒷받침되지 않아요.', example_en_3 = 'Making an inference requires reasoning beyond the facts given.', example_ko_3 = '추론은 주어진 사실 이상의 추리가 필요해요.', example_en_4 = 'Her inference was logical but not conclusive.', example_ko_4 = '그녀의 추론은 논리적이었지만 결정적이지는 않았어요.', example_en_5 = 'Readers are expected to draw their own inferences.', example_ko_5 = '독자들은 스스로 추론을 이끌어내도록 기대돼요.' WHERE id = 'w_academic_B2_08';

UPDATE words SET example_en_2 = 'The study was criticized for its lack of validity.', example_ko_2 = '연구는 타당성 부족으로 비판을 받았어요.', example_en_3 = 'Internal validity refers to the accuracy of the study''s conclusions.', example_ko_3 = '내적 타당성은 연구 결론의 정확성을 의미해요.', example_en_4 = 'Pilot testing helped to establish the validity of the instrument.', example_ko_4 = '사전 테스트는 도구의 타당성을 확립하는 데 도움이 됐어요.', example_en_5 = 'She questioned the validity of the assumptions underlying the model.', example_ko_5 = '그녀는 모델의 기반이 되는 가정들의 타당성에 의문을 제기했어요.' WHERE id = 'w_academic_B2_09';

UPDATE words SET example_en_2 = 'The test showed high reliability across different groups.', example_ko_2 = '테스트는 서로 다른 집단에 걸쳐 높은 신뢰도를 보여줬어요.', example_en_3 = 'Reliability is measured by repeating the test and comparing results.', example_ko_3 = '신뢰도는 테스트를 반복하고 결과를 비교하여 측정돼요.', example_en_4 = 'She chose a validated scale with high reliability.', example_ko_4 = '그녀는 높은 신뢰도를 가진 검증된 척도를 선택했어요.', example_en_5 = 'Low reliability can undermine the credibility of your findings.', example_ko_5 = '낮은 신뢰도는 연구 결과의 신뢰성을 약화시킬 수 있어요.' WHERE id = 'w_academic_B2_10';

UPDATE words SET example_en_2 = 'Triangulation was used to cross-check the interview data.', example_ko_2 = '인터뷰 데이터를 교차 확인하기 위해 삼각검증이 사용됐어요.', example_en_3 = 'Methodological triangulation strengthens the study''s credibility.', example_ko_3 = '방법론적 삼각검증은 연구의 신뢰성을 강화해요.', example_en_4 = 'She applied triangulation by using surveys, interviews, and observations.', example_ko_4 = '그녀는 설문지·인터뷰·관찰을 사용하여 삼각검증을 적용했어요.', example_en_5 = 'Triangulation reduces the impact of any single method''s limitations.', example_ko_5 = '삼각검증은 단일 방법의 한계 영향을 줄여줘요.' WHERE id = 'w_academic_B2_11';

UPDATE words SET example_en_2 = 'Confirmation bias can distort research conclusions.', example_ko_2 = '확증 편향은 연구 결론을 왜곡할 수 있어요.', example_en_3 = 'Researchers try to minimize bias in their data collection.', example_ko_3 = '연구자들은 데이터 수집에서 편향을 최소화하려고 해요.', example_en_4 = 'Selection bias occurs when the sample is not representative.', example_ko_4 = '선택 편향은 표본이 대표성이 없을 때 발생해요.', example_en_5 = 'She acknowledged that her personal views may have introduced bias.', example_ko_5 = '그녀는 자신의 개인적 견해가 편향을 도입했을 수 있다고 인정했어요.' WHERE id = 'w_academic_B2_12';

UPDATE words SET example_en_2 = 'We should not generalize these results to other cultures.', example_ko_2 = '이 결과를 다른 문화에 일반화해서는 안 돼요.', example_en_3 = 'It is risky to generalize from a small convenience sample.', example_ko_3 = '소규모 편의 표본에서 일반화하는 것은 위험해요.', example_en_4 = 'Can these findings be generalized to urban populations?', example_ko_4 = '이 연구 결과를 도시 인구에 일반화할 수 있나요?', example_en_5 = 'She was careful not to generalize beyond the scope of her data.', example_ko_5 = '그녀는 데이터 범위를 넘어 일반화하지 않도록 주의했어요.' WHERE id = 'w_academic_B2_13';

UPDATE words SET example_en_2 = 'The theoretical model does not always reflect real-world conditions.', example_ko_2 = '이론적 모델이 항상 실제 상황을 반영하지는 않아요.', example_en_3 = 'Her paper takes a theoretical rather than empirical approach.', example_ko_3 = '그녀의 논문은 경험적이라기보다 이론적 접근법을 취해요.', example_en_4 = 'This is a theoretical concept that is difficult to test directly.', example_ko_4 = '이것은 직접 테스트하기 어려운 이론적 개념이에요.', example_en_5 = 'Theoretical frameworks guide how researchers interpret data.', example_ko_5 = '이론적 틀은 연구자들이 데이터를 해석하는 방식을 안내해요.' WHERE id = 'w_academic_B2_14';

UPDATE words SET example_en_2 = 'Empiricism underpins much of modern scientific inquiry.', example_ko_2 = '경험주의는 현대 과학적 탐구의 많은 부분을 뒷받침해요.', example_en_3 = 'Philosophers of empiricism include Locke, Hume, and Berkeley.', example_ko_3 = '경험주의 철학자로는 로크, 흄, 버클리가 있어요.', example_en_4 = 'Empiricism holds that knowledge must be grounded in sensory experience.', example_ko_4 = '경험주의는 지식이 감각적 경험에 기반해야 한다고 봐요.', example_en_5 = 'Her research philosophy draws on empiricism and pragmatism.', example_ko_5 = '그녀의 연구 철학은 경험주의와 실용주의를 바탕으로 해요.' WHERE id = 'w_academic_B2_15';

UPDATE words SET example_en_2 = 'He studied rhetoric to improve his academic writing style.', example_ko_2 = '그는 학술 글쓰기 스타일을 향상시키기 위해 수사학을 공부했어요.', example_en_3 = 'Political rhetoric often simplifies complex issues.', example_ko_3 = '정치적 수사학은 복잡한 문제를 종종 단순화해요.', example_en_4 = 'Understanding rhetoric helps you recognize persuasive techniques.', example_ko_4 = '수사학을 이해하면 설득 기법을 인식하는 데 도움이 돼요.', example_en_5 = 'Classical rhetoric includes ethos, pathos, and logos.', example_ko_5 = '고전 수사학에는 에토스, 파토스, 로고스가 포함돼요.' WHERE id = 'w_academic_B2_16';

UPDATE words SET example_en_2 = 'The discourse around immigration has become increasingly polarized.', example_ko_2 = '이민에 관한 담론은 점점 양극화되고 있어요.', example_en_3 = 'Classroom discourse shapes how students think about knowledge.', example_ko_3 = '교실 담론은 학생들이 지식에 대해 생각하는 방식을 형성해요.', example_en_4 = 'He analyzed the discourse used in political speeches.', example_ko_4 = '그는 정치 연설에서 사용된 담론을 분석했어요.', example_en_5 = 'The discourse of science has its own vocabulary and conventions.', example_ko_5 = '과학의 담론은 고유한 어휘와 관례를 가지고 있어요.' WHERE id = 'w_academic_B2_17';

UPDATE words SET example_en_2 = 'She wrote a detailed critique of the theoretical framework.', example_ko_2 = '그녀는 이론적 틀에 대한 자세한 비평을 작성했어요.', example_en_3 = 'A good critique identifies both strengths and weaknesses.', example_ko_3 = '좋은 비평은 강점과 약점을 모두 파악해요.', example_en_4 = 'He submitted a critique of the methodology to the journal.', example_ko_4 = '그는 방법론에 대한 비평을 학술지에 제출했어요.', example_en_5 = 'Her critique was constructive, not merely negative.', example_ko_5 = '그녀의 비평은 단순히 부정적인 것이 아니라 건설적이었어요.' WHERE id = 'w_academic_B2_18';

UPDATE words SET example_en_2 = 'The introduction offers a synthesis of existing research.', example_ko_2 = '서론은 기존 연구의 종합을 제공해요.', example_en_3 = 'A good literature review goes beyond description to synthesis.', example_ko_3 = '좋은 문헌 검토는 설명을 넘어 종합에 이르러요.', example_en_4 = 'He achieved a creative synthesis of two different theories.', example_ko_4 = '그는 두 가지 다른 이론의 창의적인 종합을 이루었어요.', example_en_5 = 'The final chapter presents a synthesis of the key arguments.', example_ko_5 = '마지막 챕터는 주요 논증의 종합을 제시해요.' WHERE id = 'w_academic_B2_19';

UPDATE words SET example_en_2 = 'Make sure your essay is coherent from start to finish.', example_ko_2 = '에세이가 처음부터 끝까지 일관되도록 해 주세요.', example_en_3 = 'Without clear transitions, the text is not coherent.', example_ko_3 = '명확한 전환 없이는 텍스트가 일관되지 않아요.', example_en_4 = 'She revised the paragraph to make it more coherent.', example_ko_4 = '그녀는 더 일관되도록 문단을 수정했어요.', example_en_5 = 'A coherent argument flows logically from point to point.', example_ko_5 = '일관된 논증은 요점에서 요점으로 논리적으로 흘러요.' WHERE id = 'w_academic_B2_20';

UPDATE words SET example_en_2 = 'She annotated the text with her own critical comments.', example_ko_2 = '그녀는 자신의 비판적 코멘트로 텍스트에 주석을 달았어요.', example_en_3 = 'Annotating a source helps you engage with the material deeply.', example_ko_3 = '출처에 주석을 달면 자료를 깊이 이해하는 데 도움이 돼요.', example_en_4 = 'The professor asked the class to annotate the chapter before discussion.', example_ko_4 = '교수님은 토론 전에 챕터에 주석을 달도록 요청했어요.', example_en_5 = 'Students annotated the research article using digital tools.', example_ko_5 = '학생들은 디지털 도구를 사용해 연구 기사에 주석을 달았어요.' WHERE id = 'w_academic_B2_21';

UPDATE words SET example_en_2 = 'The literature review identified three main themes.', example_ko_2 = '문헌 검토는 세 가지 주요 주제를 파악했어요.', example_en_3 = 'Writing a literature review requires reading many sources.', example_ko_3 = '문헌 검토를 작성하는 것은 많은 출처를 읽어야 해요.', example_en_4 = 'Her literature review was praised for its critical depth.', example_ko_4 = '그녀의 문헌 검토는 비판적 깊이로 칭찬을 받았어요.', example_en_5 = 'The literature review reveals a clear gap in the existing research.', example_ko_5 = '문헌 검토는 기존 연구의 명확한 공백을 드러내요.' WHERE id = 'w_academic_B2_22';

UPDATE words SET example_en_2 = 'The longitudinal study followed 500 students over five years.', example_ko_2 = '종단 연구는 5년에 걸쳐 500명의 학생을 추적했어요.', example_en_3 = 'A longitudinal design is ideal for studying development.', example_ko_3 = '종단 설계는 발달을 연구하는 데 이상적이에요.', example_en_4 = 'Longitudinal data is expensive to collect but very valuable.', example_ko_4 = '종단 데이터는 수집하는 데 비용이 많이 들지만 매우 귀중해요.', example_en_5 = 'She conducted a longitudinal study on language acquisition.', example_ko_5 = '그녀는 언어 습득에 관한 종단 연구를 실시했어요.' WHERE id = 'w_academic_B2_23';

UPDATE words SET example_en_2 = 'A cross-sectional study captures a snapshot of the population.', example_ko_2 = '횡단 연구는 인구의 스냅샷을 포착해요.', example_en_3 = 'Cross-sectional data is quicker and cheaper to collect.', example_ko_3 = '횡단 데이터는 수집하기 더 빠르고 저렴해요.', example_en_4 = 'She compared the cross-sectional results with those of a longitudinal study.', example_ko_4 = '그녀는 횡단 결과와 종단 연구의 결과를 비교했어요.', example_en_5 = 'The cross-sectional design limited the ability to track change over time.', example_ko_5 = '횡단 설계는 시간에 따른 변화를 추적하는 능력을 제한했어요.' WHERE id = 'w_academic_B2_24';

UPDATE words SET example_en_2 = 'Researchers must be careful not to confuse correlation with causality.', example_ko_2 = '연구자들은 상관관계를 인과관계와 혼동하지 않도록 주의해야 해요.', example_en_3 = 'Establishing causality requires more than observational data.', example_ko_3 = '인과관계를 확립하는 것은 관찰 데이터 이상이 필요해요.', example_en_4 = 'The experiment was designed to test causality.', example_ko_4 = '실험은 인과관계를 테스트하도록 설계됐어요.', example_en_5 = 'She argued that the relationship goes beyond causality.', example_ko_5 = '그녀는 관계가 인과관계를 넘어선다고 주장했어요.' WHERE id = 'w_academic_B2_25';

UPDATE words SET example_en_2 = 'Scientists tried to replicate the famous study but failed.', example_ko_2 = '과학자들은 그 유명한 연구를 재현하려 했지만 실패했어요.', example_en_3 = 'A finding is stronger when it can be replicated.', example_ko_3 = '재현될 수 있을 때 연구 결과가 더 강력해요.', example_en_4 = 'She described the steps clearly so others could replicate the experiment.', example_ko_4 = '그녀는 다른 사람들이 실험을 재현할 수 있도록 단계를 명확하게 설명했어요.', example_en_5 = 'The inability to replicate results raises questions about validity.', example_ko_5 = '결과를 재현하지 못하는 것은 타당성에 의문을 제기해요.' WHERE id = 'w_academic_B2_26';

UPDATE words SET example_en_2 = 'She formatted her citation according to APA guidelines.', example_ko_2 = '그녀는 APA 지침에 따라 인용을 형식화했어요.', example_en_3 = 'Every citation must match an entry in the reference list.', example_ko_3 = '모든 인용은 참고 문헌 목록의 항목과 일치해야 해요.', example_en_4 = 'He forgot to include the page number in his citation.', example_ko_4 = '그는 인용에 페이지 번호를 포함하는 것을 깜박했어요.', example_en_5 = 'Online citation generators can help but should always be checked.', example_ko_5 = '온라인 인용 생성기가 도움이 될 수 있지만 항상 확인해야 해요.' WHERE id = 'w_academic_B2_27';

UPDATE words SET example_en_2 = 'She paraphrased the paragraph to avoid direct copying.', example_ko_2 = '그녀는 직접 복사를 피하기 위해 문단을 바꿔 말했어요.', example_en_3 = 'Paraphrase the original idea in your own words.', example_ko_3 = '원본 아이디어를 자신의 말로 바꿔 말해 주세요.', example_en_4 = 'Even when you paraphrase, you must still cite the source.', example_ko_4 = '바꿔 말할 때도 출처를 인용해야 해요.', example_en_5 = 'He paraphrased the findings rather than quoting them directly.', example_ko_5 = '그는 연구 결과를 직접 인용하는 대신 바꿔 말했어요.' WHERE id = 'w_academic_B2_28';

UPDATE words SET example_en_2 = 'Submitting someone else''s work as your own is plagiarism.', example_ko_2 = '다른 사람의 작업을 자신의 것으로 제출하는 것은 표절이에요.', example_en_3 = 'She was reported to the academic committee for plagiarism.', example_ko_3 = '그녀는 표절로 학사 위원회에 신고됐어요.', example_en_4 = 'Software can detect plagiarism in submitted essays.', example_ko_4 = '소프트웨어는 제출된 에세이에서 표절을 감지할 수 있어요.', example_en_5 = 'Proper citation is the best way to avoid plagiarism.', example_ko_5 = '올바른 인용이 표절을 피하는 가장 좋은 방법이에요.' WHERE id = 'w_academic_B2_29';

UPDATE words SET example_en_2 = 'Explain the rationale for your choice of research design.', example_ko_2 = '연구 설계 선택의 근거를 설명해 주세요.', example_en_3 = 'The rationale for the study is presented in the introduction.', example_ko_3 = '연구의 근거는 서론에 제시되어 있어요.', example_en_4 = 'Her rationale was clear and well-supported by prior literature.', example_ko_4 = '그녀의 근거는 명확하고 이전 문헌에 의해 잘 뒷받침됐어요.', example_en_5 = 'Without a clear rationale, the research lacks justification.', example_ko_5 = '명확한 근거 없이는 연구에 정당화가 부족해요.' WHERE id = 'w_academic_B2_30';

UPDATE words SET example_en_2 = 'Clearly define the scope of your literature review.', example_ko_2 = '문헌 검토의 범위를 명확하게 정의해 주세요.', example_en_3 = 'The scope of the study was limited to Korean high school students.', example_ko_3 = '연구의 범위는 한국 고등학생으로 한정됐어요.', example_en_4 = 'Narrowing the scope helped her focus the research question.', example_ko_4 = '범위를 좁히는 것이 연구 질문에 집중하는 데 도움이 됐어요.', example_en_5 = 'A broader scope would require a much larger sample.', example_ko_5 = '더 넓은 범위는 훨씬 더 큰 표본이 필요할 거예요.' WHERE id = 'w_academic_B2_31';

UPDATE words SET example_en_2 = 'Thematic analysis was used to identify patterns in the data.', example_ko_2 = '데이터의 패턴을 파악하기 위해 주제별 분석이 사용됐어요.', example_en_3 = 'She organized the findings into thematic categories.', example_ko_3 = '그녀는 연구 결과를 주제별 카테고리로 정리했어요.', example_en_4 = 'The thematic coding process was conducted by two researchers.', example_ko_4 = '주제별 코딩 과정은 두 명의 연구자에 의해 수행됐어요.', example_en_5 = 'A thematic approach works well with interview data.', example_ko_5 = '주제별 접근법은 인터뷰 데이터에 잘 적용돼요.' WHERE id = 'w_academic_B2_32';

UPDATE words SET example_en_2 = 'The peer review process is deliberately rigorous.', example_ko_2 = '동료 심사 과정은 의도적으로 엄격해요.', example_en_3 = 'She conducted a rigorous analysis of all available data.', example_ko_3 = '그녀는 이용 가능한 모든 데이터에 대한 엄격한 분석을 실시했어요.', example_en_4 = 'Rigorous research is reproducible and well-documented.', example_ko_4 = '엄격한 연구는 재현 가능하고 잘 문서화되어 있어요.', example_en_5 = 'The committee praised the study for its rigorous methodology.', example_ko_5 = '위원회는 엄격한 방법론으로 연구를 칭찬했어요.' WHERE id = 'w_academic_B2_33';

UPDATE words SET example_en_2 = 'She attempted to refute the opposing argument with new data.', example_ko_2 = '그녀는 새로운 데이터로 반대 주장을 반박하려고 했어요.', example_en_3 = 'The study could not refute the original hypothesis.', example_ko_3 = '연구는 원래 가설을 반박할 수 없었어요.', example_en_4 = 'He refuted the theory in a strongly worded paper.', example_ko_4 = '그는 강한 어조의 논문에서 이론을 반박했어요.', example_en_5 = 'Can you refute this claim using evidence from the text?', example_ko_5 = '텍스트의 증거를 사용해 이 주장을 반박할 수 있나요?' WHERE id = 'w_academic_B2_34';

UPDATE words SET example_en_2 = 'She used three studies to substantiate her claim.', example_ko_2 = '그녀는 세 개의 연구로 주장을 입증했어요.', example_en_3 = 'The findings substantiate the need for policy change.', example_ko_3 = '연구 결과는 정책 변화의 필요성을 입증해요.', example_en_4 = 'Without evidence, you cannot substantiate your argument.', example_ko_4 = '증거 없이는 주장을 입증할 수 없어요.', example_en_5 = 'He substantiated his point with data from a government report.', example_ko_5 = '그는 정부 보고서의 데이터로 요점을 입증했어요.' WHERE id = 'w_academic_B2_35';

